// Combina config + grupos (parsing JSONB) y termina si la notificación
// está desactivada o no hay grupos.
function parseJsonField(v, fb) {
  if (v == null) return fb;
  if (Array.isArray(v) || typeof v === 'object') return v;
  if (typeof v === 'string') { try { return JSON.parse(v); } catch (_) { return fb; } }
  return fb;
}

const configs = $('GET Config').all().map(i => i.json).filter(c => c && c.id);
const grupos  = $('GET Grupos').all().map(i => i.json).filter(g => g && g.id);
const config  = configs[0];

if (!config || config.activo === false) {
  // Desactivado: devolvemos array vacío para que la cadena posterior
  // no haga nada.
  return [];
}
if (grupos.length === 0) return [];

config.secciones_seguimiento = parseJsonField(config.secciones_seguimiento, []);
for (const g of grupos) {
  g.filtro_tpv       = parseJsonField(g.filtro_tpv, []);
  g.filtro_secciones = parseJsonField(g.filtro_secciones, []);
}

return [{ json: { config, grupos, disparador: 'cron' } }];

// Devuelve un item por tarea "sin avance" con los metadatos calculados.
const { config } = $('Combinar Config').first().json;
const data = $input.first().json;
const tasks = Array.isArray(data) ? data : (data.data || data.tasks || []);

const seccionesSet = new Set(config.secciones_seguimiento || []);
const projectId    = String(config.asana_project_id);
const umbralMs     = (config.umbral_dias || 7) * 24 * 60 * 60 * 1000;
const ahora        = Date.now();

function seccionEnProyecto(t) {
  const ms = Array.isArray(t.memberships) ? t.memberships : [];
  const own = ms.find(m => m && m.project && String(m.project.gid) === projectId);
  if (own && own.section && own.section.name) return own.section.name;
  return null;
}
function getTPV(t) {
  const cfs = Array.isArray(t.custom_fields) ? t.custom_fields : [];
  const c = cfs.find(x => (x && x.name && x.name.toLowerCase().trim() === 'tpv'));
  if (!c) return '';
  return c.display_value || (c.enum_value && c.enum_value.name) || c.text_value || '';
}
function diasDesde(iso) {
  if (!iso) return null;
  const t = new Date(iso).getTime();
  if (isNaN(t)) return null;
  return Math.floor((ahora - t) / (24*60*60*1000));
}

const stale = [];
for (const t of tasks) {
  if (!t || t.completed) continue;
  const sec = seccionEnProyecto(t);
  if (!sec || !seccionesSet.has(sec)) continue;
  const refIso = t.modified_at || t.created_at;
  const ref = refIso ? new Date(refIso).getTime() : 0;
  if (!ref || (ahora - ref) < umbralMs) continue;
  stale.push({
    json: {
      gid: t.gid,
      nombre: t.name || '(Sin nombre)',
      seccion: sec,
      tpv: getTPV(t) || 'Sin TPV',
      asignado: (t.assignee && t.assignee.name) || '',
      permalink: t.permalink_url || '',
      created_at: t.created_at,
      modified_at: t.modified_at,
      dias_creada: diasDesde(t.created_at),
      dias_inactiva: diasDesde(refIso)
    }
  });
}
return stale;

// Empareja por índice cada respuesta con la tarea y adjunta el último
// comentario real (resource_subtype='comment_added').
const tareas     = $('Filtrar tareas sin avance').all();
const respuestas = $input.all();

function extraerUltimoComentario(resp) {
  if (!resp || !resp.json) return null;
  const data = resp.json.data || resp.json || [];
  const comments = (Array.isArray(data) ? data : [])
      .filter(s => s && s.resource_subtype === 'comment_added')
      .sort((a, b) => String(a.created_at || '').localeCompare(String(b.created_at || '')));
  const last = comments.length ? comments[comments.length - 1] : null;
  if (!last) return null;
  return {
    autor: (last.created_by && last.created_by.name) || '—',
    fecha: last.created_at || '',
    texto: (last.text || '').trim()
  };
}

return tareas.map((t, i) => ({
  json: { ...t.json, ultimoComentario: extraerUltimoComentario(respuestas[i]) }
}));

// Compone un item por email a enviar (un grupo = un email). Cada item
// trae los metadatos para el envío + un snapshot de las tareas para
// guardar en historial.
const { config, grupos, disparador } = $('Combinar Config').first().json;
const tareas = $input.all().map(i => i.json);
const result = [];

const esc = s => String(s == null ? '' : s)
  .replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
const fmtFecha = iso => {
  if (!iso) return '—';
  const d = new Date(iso);
  if (isNaN(d.getTime())) return String(iso);
  return d.toLocaleDateString('es-ES', { day:'2-digit', month:'short', year:'numeric' });
};
const fechaEnvio = new Date().toLocaleDateString('es-ES', { day:'2-digit', month:'long', year:'numeric' });

for (const grupo of grupos) {
  let lista = [...tareas];
  if (grupo.filtro_tpv && grupo.filtro_tpv.length) {
    const set = new Set(grupo.filtro_tpv);
    lista = lista.filter(t => set.has(t.tpv));
  }
  if (grupo.filtro_secciones && grupo.filtro_secciones.length) {
    const set = new Set(grupo.filtro_secciones);
    lista = lista.filter(t => set.has(t.seccion));
  }
  if (lista.length === 0) {
    // Aun sin tareas registramos en historial que el grupo se evaluó y
    // no había nada que enviar (línea 'sin envío' = total 0).
    result.push({
      json: {
        grupo_id: grupo.id,
        grupo_nombre: grupo.nombre,
        destinatarios: grupo.destinatarios,
        umbral_dias: config.umbral_dias,
        total: 0,
        tareas: [],
        subject: null,
        html: null,
        skip_send: true,
        disparador
      }
    });
    continue;
  }

  lista.sort((a, b) => (b.dias_inactiva || 0) - (a.dias_inactiva || 0));

  const filas = lista.map(t => {
    const c = t.ultimoComentario;
    const cmtBlock = c
      ? `<div style="margin-top:8px;padding:10px 12px;background:#f8fafc;border-left:3px solid #cbd5e1;border-radius:0 8px 8px 0;font-size:12px;color:#475569;line-height:1.5">
            <div style="font-weight:700;color:#1e293b;margin-bottom:4px">${esc(c.autor)} · <span style="color:#94a3b8;font-weight:500">${esc(fmtFecha(c.fecha))}</span></div>
            <div style="white-space:pre-wrap">${esc(c.texto).replace(/\n/g,'<br>')}</div>
          </div>`
      : `<div style="margin-top:8px;padding:10px 12px;background:#fef9c3;border-left:3px solid #facc15;border-radius:0 8px 8px 0;font-size:12px;color:#854d0e">Sin comentarios todavía en la tarea.</div>`;
    const tagDias = `<span style="display:inline-block;padding:2px 8px;border-radius:999px;background:#fee2e2;color:#b91c1c;font-size:11px;font-weight:700;margin-left:6px">${t.dias_inactiva || t.dias_creada} días</span>`;
    return `<tr><td style="padding:14px 18px;border-bottom:1px solid #f1f5f9">
        <div><a href="${esc(t.permalink)}" target="_blank" style="color:#fc5858;font-weight:700;text-decoration:none;font-size:14px">${esc(t.nombre)}</a>${tagDias}</div>
        <div style="font-size:11px;color:#64748b;margin-top:3px"><strong>${esc(t.tpv)}</strong> · ${esc(t.seccion)}${t.asignado ? ' · ' + esc(t.asignado) : ''}</div>
        ${cmtBlock}
      </td></tr>`;
  }).join('');

  const total = lista.length;
  const subject = `Yurest · ${total} integració${total !== 1 ? 'n pendientes' : 'n pendiente'} sin avance · ${grupo.nombre}`;
  const html = `<!DOCTYPE html>
<html lang="es"><body style="margin:0;padding:0;background:#f1f5f9;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif">
<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background:#f1f5f9;padding:32px 16px">
<tr><td align="center"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="max-width:680px">
<tr><td style="background:linear-gradient(135deg,#0f172a,#3a0f0f);border-radius:14px 14px 0 0;padding:26px 32px">
<p style="margin:0;font-size:11px;font-weight:700;letter-spacing:.14em;text-transform:uppercase;color:#fca5a5">Yurest · Integraciones</p>
<p style="margin:8px 0 0;font-size:20px;font-weight:700;color:#fff">${total} cliente${total !== 1 ? 's' : ''} sin contestar</p>
<p style="margin:6px 0 0;font-size:12px;color:#cbd5e1">${esc(grupo.nombre)} · resumen del ${esc(fechaEnvio)}</p>
</td></tr>
<tr><td style="background:#fff;padding:20px 28px;font-size:13px;color:#334155;line-height:1.55;border-bottom:1.5px solid #f1f5f9">
Las siguientes tareas llevan más de <strong>${config.umbral_dias} días</strong> en una sección de seguimiento sin movimiento. A continuación se incluye el último comentario registrado en Asana, para que sirva de contexto al retomar el contacto con el cliente.
</td></tr>
<tr><td style="background:#fff"><table width="100%" cellpadding="0" cellspacing="0" border="0">${filas}</table></td></tr>
<tr><td style="background:#f8fafc;border-radius:0 0 14px 14px;border-top:1.5px solid #e2e8f0;padding:14px 32px;font-size:11px;color:#94a3b8">© Yurest · Aviso semanal automático generado desde el panel de Integraciones</td></tr>
</table></td></tr></table></body></html>`;

  result.push({
    json: {
      grupo_id: grupo.id,
      grupo_nombre: grupo.nombre,
      destinatarios: grupo.destinatarios,
      umbral_dias: config.umbral_dias,
      total,
      tareas: lista.map(t => ({
        gid: t.gid,
        nombre: t.nombre,
        seccion: t.seccion,
        tpv: t.tpv,
        asignado: t.asignado,
        permalink: t.permalink,
        dias_inactiva: t.dias_inactiva,
        dias_creada: t.dias_creada,
        ultimoComentario: t.ultimoComentario
      })),
      subject,
      html,
      skip_send: false,
      disparador
    }
  });
}

return result;

// El nodo emailSend reemplaza el JSON del item con la respuesta SMTP
// (accepted, messageId, etc.) perdiendo nuestros datos originales
// (grupo_id, tareas, destinatarios…). Aquí los restauramos: tomamos los
// items que pasaron el IF (skip_send=false) por su orden original en
// `Construir emails por grupo` y los emparejamos por índice con las
// respuestas de `Enviar email`.
const originales = $('Construir emails por grupo').all()
    .map(i => i.json)
    .filter(j => !j.skip_send);
const respuestas = $input.all();

return originales.map((orig, i) => {
  const r = (respuestas[i] && respuestas[i].json) || {};
  // continueOnFail mete `error` en el json cuando falla el envío.
  const hadError = r.error ? true : false;
  const errorMsg = hadError
    ? (typeof r.error === 'string' ? r.error : (r.error.message || JSON.stringify(r.error)))
    : null;
  return {
    json: {
      ...orig,
      email_enviado: !hadError,
      error: errorMsg
    }
  };
});

// Recibe items de DOS branches:
//   - Skip path (IF false=skip_send=true): item con grupo_id, total=0, etc.
//   - Send path (IF true → Enviar email → Restaurar datos): item con
//     todos los datos originales + email_enviado + error.
// Los normaliza al esquema de la tabla notif_integraciones_historial.
const items = $input.all();
const out = [];
for (const it of items) {
  const j = it.json || {};
  const skip = !!j.skip_send;
  // Para items del send path la flag email_enviado viene fijada en
  // "Restaurar datos". Para items del skip path no existe.
  const enviado = skip ? false : (j.email_enviado !== false);
  const errorMsg = skip ? 'sin tareas que enviar' : (j.error || null);
  out.push({
    json: {
      grupo_id:      j.grupo_id || null,
      grupo_nombre:  j.grupo_nombre || '—',
      destinatarios: j.destinatarios || '',
      total_tareas:  j.total || 0,
      umbral_dias:   j.umbral_dias || 0,
      tareas:        JSON.stringify(j.tareas || []),
      email_enviado: enviado,
      error:         errorMsg,
      disparador:    j.disparador || 'cron'
    }
  });
}
return out;
